var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"침식체 머리통이 하나~ 침식체 머리통이 둘~","JPN":"侵食体の頭ひと～つ、侵食体の頭ふた～つ……","ENG":"That's a C.O.'s head, and that's another one.","TWN":"一個侵蝕體腦袋瓜～兩個侵蝕體腦袋瓜～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아이쿠, 얘는 머리가 실하게 익었네. 우량아인가 봐.","JPN":"あらあら、この子は頭がずいぶんデカいね。健康優良児ってやつ？","ENG":"Whoa, this one's got a real big head. Maybe it used to eat a lot.","TWN":"哎呀呀，這傢伙的腦袋長得可真大。看來是個健康寶寶呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"눈에 뭐라도 들어갔어? 아까부터 계속 인상 찌푸리고 있네?","JPN":"目にゴミでも入った？　さっきから眉間にしわが寄ってるけど？","ENG":"Do you have something in your eyes? Why are you frowning?","TWN":"有什麼東西了跑進妳眼睛裡了嗎？妳從剛才開始皺著眉頭耶？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......노려보는 거예요.","JPN":"……睨んでいるのです。","ENG":"I'm staring.","TWN":"……我是在瞪人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"왜? 아직 살아 있는 침식체라도 있어? 어디어디?","JPN":"何で？　まだ生きてる侵食体でもいた？　どこどこ？","ENG":"At what? Do you see a living C.O. anywhere? Where is it?","TWN":"為什麼？還有活著的侵蝕體嗎？哪裡哪裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"침식체가 아니라 당신이요! 당신을 노려보고 있는 거라고요!","JPN":"侵食体ではなく、あなたです！　あなたを睨んでいるのです！","ENG":"I'm talking about you! I've been staring at you!","TWN":"不是瞪侵蝕體，是在瞪妳！我是在瞪著妳！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 돈 떼먹힐까 봐 불안해?","JPN":"もしかして、報酬を独り占めされるのが心配？","ENG":"Come on, you're worried that I'd keep all the money to myself, aren't you?","TWN":"噢，擔心我把錢私吞了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이래 봬도 계산은 확실히 한다구. 사냥 수당 받으면 네 몫은 제대로 나눠 줄게.","JPN":"こう見えても、計算はしっかりする主義なんだよね。報酬をもらったら、アンタの分はちゃんと分けるから。","ENG":"I'm a fair person and a sincere partner. You'll get your share when they pay me for these heads.","TWN":"別看我這樣，我會好好算帳的。拿到狩獵津貼的話，妳那一份會好好分給妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 그래요?","JPN":"ああ、そうですか。","ENG":"Oh, really?","TWN":"啊，是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"관리국도 신경 끄는 곳인데 수당이 어디서 나오나요?","JPN":"でも、管理局にも見放された場所なのに、報酬はどこから出るのです？","ENG":"And who's going to pay you? The Administration doesn't even know about this place.","TWN":"這裡連管理局都沒心去管了，去哪裡拿津貼啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그야 맥크레디 가문의 금고에서 나오겠지? 날 고용한 사람이 학회장이니까.","JPN":"そりゃ、マクレディー家の金庫からでしょ。アタシを雇ったのは学会長だし。","ENG":"The MacCready family, I guess? I was employed by the President of the Society herself.","TWN":"那當然是從麥克蕾蒂家的金庫裡拿呀？畢竟雇用我的人是學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 저희 가문의 자산과 학회장이 대체 무슨 상관이죠?","JPN":"え？　マクレディー家の資産と学会長に何の関係が？","ENG":"Huh? What's the President doing with my family's assets?","TWN":"咦？我家族的財產和學會長到底有什麼關係？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 레지나는 모르겠구나.","JPN":"ああ、レジーナは知らないんだね。","ENG":"Ah, you haven't heard, I guess.","TWN":"啊，蕾佳娜不知道啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네가 없는 동안 맥크레디 가문은 학회장이 대신 관리하고 있었어.","JPN":"アンタがいない間、マクレディー家は学会長が代わりに管理してるんだよ。","ENG":"The President has been taking care of the MacCready family while you were gone.","TWN":"妳不在的時候，麥克蕾蒂家族是由學會長代為管理的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하......!","JPN":"えっ……！","ENG":"Ha!","TWN":"啥……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 에델이란 작자, 후견인 행세를 하면서 남의 집안 재산을 자기 지갑처럼 쓰나 보군요.","JPN":"そのエデルという方が……後見人として振る舞いながら、よその家の財産を自分の財布のように使っているのですね。","ENG":"This Edel wench must be spending the family money like water, pretending to be the guardian.","TWN":"看來那個叫艾瑟兒的傢伙，裝作監護人的樣子，一邊把別人家的財產當自己的錢包用呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻게 감히......","JPN":"それも、我がマクレディー家の……","ENG":"How dare she!","TWN":"她竟敢……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 어서 길을 안내하세요. 서둘러야겠습니다.","JPN":"リベット、案内してください。急がなければなりません。","ENG":"Lead the way, Rivet. We have to hurry.","TWN":"里維，快點帶路吧，我趕時間。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};